# Core module providing base classes and fundamental types
# No imports - this is the base module

interface IIdentifiable:
    def get_id(self) -> int: ...

@abstract
class Entity:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def describe(self) -> str:
        return f"Entity: {self.name}"

    @abstract
    def get_type(self) -> str: ...

class Person(Entity, IIdentifiable):
    age: int
    id_counter: int = 1

    def __init__(self, name: str, age: int):
        super().__init__(name)
        self.age = age
        self._id: int = Person.id_counter
        Person.id_counter += 1

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base}, Age: {self.age}"

    @override
    def get_type(self) -> str:
        return "Person"

    @override
    def get_id(self) -> int:
        return self._id

