# Widget module with interface implementation
# Only imports from core (base module) to avoid circular dependency

from core import IIdentifiable, Entity

interface Drawable:
    def draw(self) -> str: ...

class Widget(Entity, Drawable):
    width: int
    height: int

    def __init__(self, name: str, width: int, height: int):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def get_type(self) -> str:
        return "Widget"

    @override
    def draw(self) -> str:
        return f"Drawing {self.name} ({self.width}x{self.height})"

class Button(Widget):
    label: str

    def __init__(self, name: str, width: int, height: int, label: str):
        super().__init__(name, width, height)
        self.label = label

    @override
    def draw(self) -> str:
        base: str = super().draw()
        return f"{base} [Button: {self.label}]"
